//=============================================================================
// LPText.js
//=============================================================================

window.LOGICPULSE = window.LOGICPULSE || {};
LOGICPULSE.UI = LOGICPULSE.UI || {};

//=============================================================================
// Text
//=============================================================================

LOGICPULSE.UI.Text = class extends Sprite {

    constructor(options = {}) {

        super();

        this._width = options.width ?? 100;
        this._height = options.height ?? 32;

        this.bitmap = new Bitmap(
            this._width,
            this._height
        );

        this.bitmap.fontFace =
            options.fontFace ?? $gameSystem.mainFontFace();

        this.bitmap.fontSize =
            options.fontSize ?? 20;

        this.bitmap.textColor =
            options.textColor ?? "#FFFFFF";

        this.bitmap.outlineColor =
            options.outlineColor ?? "rgba(0,0,0,0.8)";

        this.bitmap.outlineWidth =
            options.outlineWidth ?? 4;

        this._align =
            options.align ?? "left";

        this._padding =
            options.padding ?? 0;

        this._lineHeight =
            options.lineHeight ??
            (this.bitmap.fontSize + 6);

        this.move(
            options.x ?? 0,
            options.y ?? 0
        );

        this.setText(
            options.text ?? ""
        );

    }

    //--------------------------------
    // Set Text
    //--------------------------------

    setText(text) {

        text = String(text);

        if (this._text === text) {

            return;

        }

        this._text = text;

        this.refresh();

    }

    //--------------------------------
    // Refresh
    //--------------------------------

    refresh() {

        this.bitmap.clear();

        const lines = this.wrapText(this._text);

        let y = this._padding;

        for (const line of lines) {

            this.bitmap.drawText(

                line,

                this._padding,

                y,

                this._width - this._padding * 2,

                this._lineHeight,

                this._align

            );

            y += this._lineHeight;

        }

    }

    //--------------------------------
    // Word Wrap
    //--------------------------------

    wrapText(text) {

        if (!text) {

            return [];

        }

        const maxWidth =
            this._width - this._padding * 2;

        const words = text.split(" ");

        const lines = [];

        let line = "";

        for (const word of words) {

            const test =
                line ? line + " " + word : word;

            const width =
                this.bitmap.measureTextWidth(test);

            if (

                width > maxWidth &&
                line.length > 0

            ) {

                lines.push(line);

                line = word;

            }

            else {

                line = test;

            }

        }

        if (line.length > 0) {

            lines.push(line);

        }

        return lines;

    }

    //--------------------------------
    // Text
    //--------------------------------

    text() {

        return this._text;

    }

};


//=============================================================================
// LPScrollText.js
//=============================================================================

window.LOGICPULSE = window.LOGICPULSE || {};
LOGICPULSE.UI = LOGICPULSE.UI || {};

//=============================================================================
// Scroll Text
//=============================================================================

LOGICPULSE.UI.ScrollText = class extends LOGICPULSE.UI.Element {

    constructor(options = {}) {

        super();

        this._width =
            options.width ?? 200;

        this._height =
            options.height ?? 100;

        this._padding =
            options.padding ?? 0;

        this._lineHeight =
            options.lineHeight ?? 28;

        this._fontSize =
            options.fontSize ?? 20;

        this._scroll = 0;

        this._maxScroll = 0;

        this._contentHeight = 0;

        this.move(

            options.x ?? 0,
            options.y ?? 0

        );

        this.create();

    }

    //--------------------------------
    // Create
    //--------------------------------

    create() {

        this.createMask();
        this.createText();

    }

    //--------------------------------
    // Mask
    //--------------------------------

    createMask() {

        this._maskGraphic = new PIXI.Graphics();

        this._maskGraphic.beginFill(0xffffff);

        this._maskGraphic.drawRect(

            0,
            0,
            this._width,
            this._height

        );

        this._maskGraphic.endFill();

        this.addChild(

            this._maskGraphic

        );

    }

    //--------------------------------
    // Text
    //--------------------------------

    createText() {

        this._textSprite = new Sprite();

        this._textSprite.bitmap = new Bitmap(

            this._width,
            2000

        );

        this._textSprite.bitmap.fontFace =
            $gameSystem.mainFontFace();

        this._textSprite.bitmap.fontSize =
            this._fontSize;

        this._textSprite.bitmap.outlineWidth = 4;

        this._textSprite.bitmap.outlineColor =
            "rgba(0,0,0,0.8)";

        this._textSprite.mask =
            this._maskGraphic;

        this.addChild(

            this._textSprite

        );

    }

    //--------------------------------
    // Set Text
    //--------------------------------

    setText(text) {

        text = String(text ?? "");

        this._textSprite.bitmap.clear();

        this.drawWrappedText(text);

        this.resetScroll();

    }

    //--------------------------------
    // Draw Wrapped Text
    //--------------------------------

    drawWrappedText(text) {

        const bitmap =
            this._textSprite.bitmap;

        const maxWidth =
            this._width - this._padding * 2;

        const words =
            text.split(/\s+/);

        let line = "";

        let y = 0;

        for (const word of words) {

            const test =

                line.length
                    ? line + " " + word
                    : word;

            const width =
                bitmap.measureTextWidth(test);

            if (

                width > maxWidth &&

                line.length

            ) {

                bitmap.drawText(

                    line,

                    this._padding,

                    y,

                    maxWidth,

                    this._lineHeight,

                    "left"

                );

                line = word;

                y += this._lineHeight;

            }

            else {

                line = test;

            }

        }

        if (line.length) {

            bitmap.drawText(

                line,

                this._padding,

                y,

                maxWidth,

                this._lineHeight,

                "left"

            );

            y += this._lineHeight;

        }

        this._contentHeight = y;

        this._maxScroll = Math.max(

            0,

            this._contentHeight - this._height

        );

    }

    //--------------------------------
    // Scroll
    //--------------------------------

    scroll(amount) {

        if (this._maxScroll <= 0) {

            return;

        }

        this._scroll += amount;

        if (this._scroll < 0) {

            this._scroll = 0;

        }

        if (this._scroll > this._maxScroll) {

            this._scroll = this._maxScroll;

        }

        this._textSprite.y = -this._scroll;

    }

    //--------------------------------
    // Can Scroll
    //--------------------------------

    canScroll() {

        return this._maxScroll > 0;

    }

    //--------------------------------
    // Reset Scroll
    //--------------------------------

    resetScroll() {

        this._scroll = 0;

        this._textSprite.y = 0;

    }

};


//=============================================================================
// LPGridSlot.js
//=============================================================================

window.LOGICPULSE = window.LOGICPULSE || {};
LOGICPULSE.UI = LOGICPULSE.UI || {};

//=============================================================================
// Grid Slot
//=============================================================================

LOGICPULSE.UI.GridSlot = class extends LOGICPULSE.UI.Element {

    constructor(options = {}) {

        super();

        this._entry = options.entry || null;

        this._focused = false;
        this._locked = false;

        this.move(

            options.x ?? 0,
            options.y ?? 0

        );

        this.create();

    }

    //--------------------------------
    // Create
    //--------------------------------

    create() {

        this.createBackground();
        this.createIcon();
        this.createAmount();
        this.createSelectionFrame();

        this.updateSelection();

    }

    //--------------------------------
    // Refresh
    //--------------------------------

    refresh() {

        this.removeChildren();

        this.create();

    }

    //--------------------------------
    // Background
    //--------------------------------

    createBackground() {

        const image = this.getBackgroundImage();

        this._background = this.createSprite(

            LOGICPULSE.Assets.Folders.Inventory,
            image

        );

    }

    //--------------------------------
    // Icon
    //--------------------------------

    createIcon() {

        const item = this.item();

        if (!item) {

            return;

        }

        this._icon = LOGICPULSE.Assets.createItemSprite(

            item

        );

        const offset =

            LOGICPULSE.Layout.Inventory.Grid.Icon.offset;

        this._icon.x = offset.x;
        this._icon.y = offset.y;

        this.addChild(this._icon);

    }

    //--------------------------------
    // Amount
    //--------------------------------


    createAmount() {

        if (this.amount() <= 1) {

            return;

        }


        const layout =
            LOGICPULSE.Layout.Inventory.Amount;

        this._amountText = this.createText({

            text: this.amount(),

            x: layout.x,

            y: layout.y,

            width: layout.width,

            height: layout.height,

            align: layout.align,

            fontSize: layout.fontSize

        });

    }

    //--------------------------------
    // Selection Frame
    //--------------------------------

    createSelectionFrame() {

        this._selectionFrame = this.createSprite(

            LOGICPULSE.Assets.Folders.Inventory,

            LOGICPULSE.Assets.Images.Inventory.SelectionFrame

        );

        this._selectionFrame.visible = false;

    }

    //--------------------------------
    // Background Image
    //--------------------------------

    getBackgroundImage() {

        switch (this.rarity()) {

            case 3:

                return LOGICPULSE.Assets.Images.Inventory.ItemBoxLegendary;

            case 2:

                return LOGICPULSE.Assets.Images.Inventory.ItemBoxRare;

            default:

                return LOGICPULSE.Assets.Images.Inventory.ItemBoxCommon;

        }

    }

    //--------------------------------
    // Focus
    //--------------------------------

    setFocused(value) {

        if (this._focused === value) {

            return;

        }

        this._focused = value;

        this.updateSelection();

    }

    //--------------------------------
    // Locked
    //--------------------------------

    setLocked(value) {

        if (this._locked === value) {

            return;

        }

        this._locked = value;

        this.updateSelection();

    }

    //--------------------------------
    // Focused
    //--------------------------------

    focused() {

        return this._focused;

    }

    //--------------------------------
    // Locked
    //--------------------------------

    locked() {

        return this._locked;

    }

    //--------------------------------
    // Update Selection
    //--------------------------------

    updateSelection() {

        if (!this._selectionFrame) {

            return;

        }

        if (this._locked) {

            this._selectionFrame.visible = true;

            this._selectionFrame.alpha = 1.0;

            LOGICPULSE.Animator.stop(

                this._selectionFrame

            );

            return;

        }

        if (this._focused) {

            this._selectionFrame.visible = true;

            LOGICPULSE.Animator.pulse(

                this._selectionFrame

            );

        } else {

            this._selectionFrame.visible = false;

            LOGICPULSE.Animator.stop(

                this._selectionFrame

            );

        }

    }

    //--------------------------------
    // Entry
    //--------------------------------

    entry() {

        return this._entry;

    }

    //--------------------------------
    // Item
    //--------------------------------

    item() {

        return this._entry?.item ?? null;

    }

    //--------------------------------
    // Amount
    //--------------------------------

    amount() {

        return this._entry?.amount ?? 0;

    }

    //--------------------------------
    // Rarity
    //--------------------------------

    rarity() {

        return this._entry?.rarity ?? 1;

    }

    //--------------------------------
    // Category
    //--------------------------------

    category() {

        return this._entry?.category ?? null;

    }

};


//=============================================================================
// LPGrid.js
//=============================================================================

window.LOGICPULSE = window.LOGICPULSE || {};
LOGICPULSE.UI = LOGICPULSE.UI || {};

//=============================================================================
// Grid
//=============================================================================

LOGICPULSE.UI.Grid = class extends LOGICPULSE.UI.Element {

    constructor(layout) {

        super();

        this._layout = layout;

        this._category =
            LOGICPULSE.Constants.Category.Consumable;

        this._selectedIndex = 0;

        this._scrollRow = 0;

        this._visibleRows = Math.floor(

            this._layout.rect.height /

            this._layout.spacingY

        );

        this._scrollTargetY = 0;

        this._slots = [];

        this.create();

    }

    //--------------------------------
    // Create
    //--------------------------------

    create() {

        this.createMask();
        this.createViewport();

    }

    //--------------------------------
    // Mask
    //--------------------------------

    createMask() {

        const mask = this._layout.mask;

        this._maskGraphic = new PIXI.Graphics();

        this._maskGraphic.beginFill(0xffffff);

        this._maskGraphic.drawRect(

            mask.x,
            mask.y,
            mask.width,
            mask.height

        );

        this._maskGraphic.endFill();

        this.addChild(this._maskGraphic);

        this.mask = this._maskGraphic;

    }

    //--------------------------------
    // Viewport
    //--------------------------------

    createViewport() {

        this._viewport = new PIXI.Container();

        this.addChild(this._viewport);

        this.createLayers();

    }

    //--------------------------------
    // Layers
    //--------------------------------

    createLayers() {

        this._slotLayer = new PIXI.Container();
        this._iconLayer = new PIXI.Container();
        this._cursorLayer = new PIXI.Container();

        this._viewport.addChild(this._slotLayer);
        this._viewport.addChild(this._iconLayer);
        this._viewport.addChild(this._cursorLayer);

        this.buildGrid();

    }

    //--------------------------------
    // Grid
    //--------------------------------

    buildGrid() {

        this.clearSlots();

        this.buildSlots();

        this.updateViewport();

        this.setSelectedIndex(

            this._selectedIndex

        );

    }

    //--------------------------------
    // Clear Slots
    //--------------------------------

    clearSlots() {

        this._slotLayer.removeChildren();

        this._slots = [];

    }

    //--------------------------------
    // Build Slots
    //--------------------------------

    buildSlots() {

        const items = this.items();

        for (let index = 0; index < items.length; index++) {

            const position = this.slotPosition(index);

            const slot = new LOGICPULSE.UI.GridSlot({

                x: position.x,

                y: position.y,

                entry: items[index]

            });

            this._slotLayer.addChild(slot);

            this._slots.push(slot);

        }

    }

    //--------------------------------
    // Slot Position
    //--------------------------------

    slotPosition(index) {

        const layout = this._layout;

        return {

            x:

                layout.rect.x +
                ((index % layout.columns) * layout.spacingX),

            y:

                layout.rect.y +
                (Math.floor(index / layout.columns) * layout.spacingY)

        };

    }

    //--------------------------------
    // Set Category
    //--------------------------------

    setCategory(category) {

        if (this._category === category) {

            return;

        }

        this._category = category;

        this._selectedIndex = 0;

        this._scrollRow = 0;

        this._scrollTargetY = 0;

        if (this._viewport) {

            this._viewport.y = 0;

        }

        this.buildGrid();

    }

    //--------------------------------
    // Category
    //--------------------------------

    category() {

        return this._category;

    }

    //--------------------------------
    // Items
    //--------------------------------

    items() {

        return LOGICPULSE.InventoryProvider.getItems(

            this._category

        );

    }

    //--------------------------------
    // Selected Index
    //--------------------------------

    selectedIndex() {

        return this._selectedIndex;

    }

    //--------------------------------
    // Set Selected Index
    //--------------------------------

    setSelectedIndex(index) {

        const max = this.items().length - 1;

        if (max < 0) {

            this._selectedIndex = -1;

            this.updateSelection();

            return;

        }

        this._selectedIndex = Math.max(

            0,

            Math.min(index, max)

        );

        this.updateSelection();

    }

    //--------------------------------
    // Selected Entry
    //--------------------------------

    selectedEntry() {

        if (this._selectedIndex < 0) {

            return null;

        }

        return this.items()[this._selectedIndex] ?? null;

    }

    //--------------------------------
    // Move Left
    //--------------------------------

    moveLeft() {

        this.setSelectedIndex(

            this._selectedIndex - 1

        );

    }

    //--------------------------------
    // Move Right
    //--------------------------------

    moveRight() {

        this.setSelectedIndex(

            this._selectedIndex + 1

        );

    }

    //--------------------------------
    // Move Up
    //--------------------------------

    moveUp() {

        this.setSelectedIndex(

            this._selectedIndex -

            this._layout.columns

        );

    }

    //--------------------------------
    // Move Down
    //--------------------------------

    moveDown() {

        this.setSelectedIndex(

            this._selectedIndex +

            this._layout.columns

        );

    }

    //--------------------------------
    // Update Selection
    //--------------------------------

    updateSelection() {

        if (!this._slots) {

            return;

        }

        for (let i = 0; i < this._slots.length; i++) {

            this._slots[i].setFocused(

                i === this._selectedIndex

            );

        }

        this.updateViewport();

    }

    //--------------------------------
    // Update Viewport
    //--------------------------------

    updateViewport() {

        if (this._selectedIndex < 0) {

            return;

        }

        const row = Math.floor(

            this._selectedIndex /

            this._layout.columns

        );

        const totalRows = Math.max(

            1,

            Math.ceil(

                this.items().length /

                this._layout.columns

            )

        );

        const maxScrollRow = Math.max(

            0,

            totalRows -

            this._visibleRows

        );

        if (row < this._scrollRow) {

            this._scrollRow = row;

        }

        else if (

            row >=

            this._scrollRow +

            this._visibleRows

        ) {

            this._scrollRow =

                row -

                this._visibleRows +

                1;

        }

        this._scrollRow = Math.max(

            0,

            Math.min(

                this._scrollRow,

                maxScrollRow

            )

        );

        this._scrollTargetY =

            -(this._scrollRow *

                this._layout.spacingY);

    }

    //--------------------------------
    // Update
    //--------------------------------

    update() {

        const speed = 0.18;

        if (

            Math.abs(

                this._viewport.y -

                this._scrollTargetY

            ) < 0.5

        ) {

            this._viewport.y =

                this._scrollTargetY;

        }

        else {

            this._viewport.y +=

                (

                    this._scrollTargetY -

                    this._viewport.y

                ) * speed;

        }

    }

};


